31	#include <pybind11/chrono.h>
32	#include <pybind11/pybind11.h>
33	#include <pybind11/stl.h>
34	#include <pybind11/functional.h>
35	
36	#include <atomic>
37	
38	#include "vectornav/HAL/Timer.hpp"
39	#include "vectornav/Implementation/MeasurementDatatypes.hpp"
40	#include "vectornav/Interface/CompositeData.hpp"
41	#include "vectornav/Interface/Exceptions.hpp"
42	#include "vectornav/Interface/Sensor.hpp"
43	
44	#include "vectornav/Interface/BridgeSensor.hpp"
45	
46	namespace py = pybind11;
47	namespace VN
48	{
49	
50	void init_sensor(py::module& m)
51	{
52	    m.def("now",[]() { return VN::now(); });
53	
54	    py::class_<Sensor>(m, "Sensor_Base")
55	        .def("verifySensorConnectivity", &Sensor::verifySensorConnectivity)
56	        .def("connectedPortName", &Sensor::connectedPortName)
57	        .def("connectedBaudRate", &Sensor::connectedBaudRate)
58	        .def("changeBaudRate",
59	        [](Sensor& vs, Sensor::BaudRate newBaudRate) {
60	            throwIfError(vs.changeBaudRate(newBaudRate));
61	        }
62	        )
63	        .def("changeBaudRate",
64	            [](Sensor& vs, Sensor::BaudRate newBaudRate,  Registers::System::BaudRate::SerialPort serialPort) {
65	              throwIfError(vs.changeBaudRate(newBaudRate, serialPort));
66	            }
67	        )
68	        .def("changeHostBaudRate",
69	        [](Sensor& vs, Sensor::BaudRate newBaudRate) {
70	            throwIfError(vs.changeHostBaudRate(newBaudRate));
71	        }
72	        )
73	        .def("disconnect", [] (Sensor& vs) {
74	            vs.disconnect();
75	        } 
76	        )
77	        // Measurement Accessor
78	        .def("hasMeasurement", &Sensor::hasMeasurement)
79	        .def("getNextMeasurement",
80	        [](Sensor& vs) -> std::optional<VN::CompositeData> {
81	            auto ownPtr = vs.getNextMeasurement();
82	            if (ownPtr) { return std::make_optional(*ownPtr); } else { return std::nullopt; }      
83	        }
84	        )
85	        .def("getNextMeasurement",
86	        [](Sensor& vs, const bool blocking) -> std::optional<VN::CompositeData> {
87	            auto ownPtr = vs.getNextMeasurement(blocking);
88	            if (ownPtr) { return std::make_optional(*ownPtr); } else { return std::nullopt; }      
89	        }
90	        )
91	        .def("getMostRecentMeasurement",
92	        [](Sensor& vs) -> std::optional<VN::CompositeData> {
93	            auto ownPtr = vs.getMostRecentMeasurement();
94	            if (ownPtr) { return std::make_optional(*ownPtr); } else { return std::nullopt; }      
95	        }
96	        )
97	        .def("getMostRecentMeasurement",
98	        [](Sensor& vs, const bool blocking) -> std::optional<VN::CompositeData> {
99	            auto ownPtr = vs.getMostRecentMeasurement(blocking);
100	            if (ownPtr) { return std::make_optional(*ownPtr); } else { return std::nullopt; }      
101	        }
102	        )
103	        // Command Sending
104	        .def("readRegister",
105	        [](Sensor& vs, Register* registerToRead, const bool retryOnFailure) {
106	            throwIfError(vs.readRegister(registerToRead, retryOnFailure));
107	        }
108	        )
109	        .def("readRegister",
110	        [](Sensor& vs, Register* registerToRead) {
111	            throwIfError(vs.readRegister(registerToRead));
112	        }
113	        )
114	        .def("writeRegister",
115	        [](Sensor& vs, ConfigurationRegister* registerToWrite, const bool retryOnFailure) {
116	            throwIfError(vs.writeRegister(registerToWrite, retryOnFailure));
117	        }
118	        )
119	        .def("writeRegister",
120	        [](Sensor& vs, ConfigurationRegister* registerToWrite) {
121	            throwIfError(vs.writeRegister(registerToWrite));
122	        }
123	        )
124	        .def("writeSettings",
125	        [](Sensor& vs) {
126	            throwIfError(vs.writeSettings());
127	        }
128	        )
129	        .def("restoreFactorySettings",
130	        [](Sensor& vs) {
131	            throwIfError(vs.restoreFactorySettings()); 
132	        }
133	        )
134	        .def("knownMagneticDisturbance",
135	        [](Sensor& vs, const KnownMagneticDisturbance::State state) {
136	            throwIfError(vs.knownMagneticDisturbance(state));
137	        }
138	        )
139	        .def("knownAccelerationDisturbance",
140	        [](Sensor& vs, const KnownAccelerationDisturbance::State state) {
141	            throwIfError(vs.knownAccelerationDisturbance(state));
142	        }
143	        )
144	        .def("setInitialHeading",
145	        [](Sensor& vs, const float heading) {
146	            throwIfError(vs.setInitialHeading(heading));
147	        }
148	        )
149	        .def("setInitialHeading",
150	        [](Sensor& vs, Ypr ypr) {
151	            throwIfError(vs.setInitialHeading(ypr));
152	        }
153	        )
154	        .def("setInitialHeading",
155	        [](Sensor& vs, Quat quat) {
156	            throwIfError(vs.setInitialHeading(quat));
157	        }
158	        )
159	        .def("asyncOutputEnable",
160	        [](Sensor& vs, const AsyncOutputEnable::State state) {
161	            throwIfError(vs.asyncOutputEnable(state));
162	        }
163	        )
164	        .def("setFilterBias",
165	        [](Sensor& vs) {
166	            throwIfError(vs.setFilterBias());
167	        }
168	        )
169	        .def("sendCommand", 
170	        [](Sensor& vs, GenericCommand* commandToSend, Sensor::SendCommandBlockMode waitMode, const Microseconds waitLength, const Microseconds timeoutThreshold) {
171	            throwIfError(vs.sendCommand(commandToSend, waitMode, waitLength, timeoutThreshold));
172	        }
173	        )
174	        .def("sendCommand", 
175	        [](Sensor& vs, GenericCommand* commandToSend, Sensor::SendCommandBlockMode waitMode, const Microseconds waitLength) {
176	            throwIfError(vs.sendCommand(commandToSend, waitMode, waitLength));
177	        }
178	        )
179	        .def("sendCommand", 
180	        [](Sensor& vs, GenericCommand* commandToSend, Sensor::SendCommandBlockMode waitMode) {
181	            throwIfError(vs.sendCommand(commandToSend, waitMode));
182	        }
183	        )
184	        .def("serialSend",
185	        [](Sensor& vs, const char* msgToSend, const size_t len) {
186	            throwIfError(vs.serialSend(msgToSend, len));
187	        }
188	        )
189	        .def("serialSend",
190	        [](Sensor& vs, const std::string& msgToSend) {
191	            throwIfError(vs.serialSend(msgToSend.c_str(), msgToSend.length()));
192	        }
193	        )
194	        // Additional Logging
195	        .def("registerReceivedByteBuffer", &Sensor::registerReceivedByteBuffer)
196	        .def("deregisterReceivedByteBuffer", &Sensor::deregisterReceivedByteBuffer)
197	        .def("subscribeToMessage",
198	            [](Sensor& vs, PacketQueue_Interface* q, const Sensor::SyncByte& b) {
199	                vs.subscribeToMessage(q, b);
200	            }
201	        )
202	        .def("subscribeToMessage",
203	        [](Sensor& vs, PacketQueue_Interface* q, const Sensor::BinaryOutputMeasurements& b, Sensor::FaSubscriberFilterType c = Sensor::FaSubscriberFilterType::ExactMatch) {
204	            throwIfError(vs.subscribeToMessage(q, b, c));
205	        }
206	        )
207	        .def("subscribeToMessage",
208	        [](Sensor& vs, PacketQueue_Interface* q, const AsciiHeader& b, Sensor::AsciiSubscriberFilterType c = Sensor::AsciiSubscriberFilterType::MeasurementStartsWith) {
209	            throwIfError(vs.subscribeToMessage(q, b, c));
210	        }
211	        )
212	        .def("subscribeToMessage",
213	        [](Sensor& vs, PacketQueue_Interface* q, Sensor::Fb00SubscriberFilter filter) {
214	            throwIfError(vs.subscribeToMessage(q, filter));
215	        }
216	        )
217	        .def("unsubscribeFromMessage",
218	            [](Sensor& vs, PacketQueue_Interface* q, const Registers::System::BinaryOutputMeasurements& b) {
219	                vs.unsubscribeFromMessage(q, b);
220	            }
221	        )
222	        .def("unsubscribeFromMessage",
223	            [](Sensor& vs, PacketQueue_Interface* q, const AsciiHeader& b) {
224	                vs.unsubscribeFromMessage(q, b);
225	            }
226	        )
227	        .def("unsubscribeFromMessage",
228	            [](Sensor& vs, PacketQueue_Interface* q, const Sensor::SyncByte& b) {
229	                vs.unsubscribeFromMessage(q, b);
230	            }
231	        )
232	        // Error Handling
233	        .def("asyncErrorQueueSize", &Sensor::asyncErrorQueueSize)
234	        .def("clearAsyncErrorQueue", &Sensor::clearAsyncErrorQueue)
235	            
236	        .def("throwIfAsyncError",
237	        [](Sensor& vs) {
238	            auto asyncError = vs.getNextAsyncError();
239	            if (asyncError) 
240	            {
241	                throwError(asyncError->error);
242	            }
243	        }
244	        )
245	#if _VN_TCP_DRIVER
246	        .def("setSerialTcpChangeBaudRate",
247	            [](Sensor& vs, std::function<Errored(uint32_t)> callback) {
248	                vs.setSerialTcpChangeBaudRate(callback);
249	            }, py::arg("callback")
250	        )
251	#endif
252	        .def("__enter__", [](Sensor& vs) {
253	        return &vs;
254	        }
255	        )
256	        .def("__exit__",
257	        [](Sensor& vs,
258	            const std::optional<pybind11::type> &exc_type,
259	            const std::optional<pybind11::object> &exc_value,
260	            const std::optional<pybind11::object> &traceback) {
261	        
262	            vs.disconnect();
263	        }
264	        )
265	        ;
266	    py::class_<BridgeSensor, Sensor> sensor(m, "Sensor");
267	
268	    py::implicitly_convertible<py::int_, BridgeSensor::BaudRate>();
269	
270	    py::enum_<BridgeSensor::MeasQueueMode>(sensor, "MeasQueueMode", py::module_local())
271	    .value("Off", BridgeSensor::MeasQueueMode::Off)
272	    .value("Force", BridgeSensor::MeasQueueMode::Force)
273	    .value("Try", BridgeSensor::MeasQueueMode::Try)
274	#if THREADING_ENABLE
275	    .value("Retry", BridgeSensor::MeasQueueMode::Retry)
276	#endif
277	    ;
278	
279	    py::enum_<Registers::System::BaudRate::SerialPort>(sensor, "SerialPort", py::module_local())
280	        .value("ActiveSerial", Registers::System::BaudRate::SerialPort::ActiveSerial)
281	        .value("Serial1", Registers::System::BaudRate::SerialPort::Serial1)
282	        .value("Serial2", Registers::System::BaudRate::SerialPort::Serial2)
283	        .value("Poll", Registers::System::BaudRate::SerialPort::Poll);
284	
285	    py::enum_<BridgeSensor::SendCommandBlockMode>(sensor, "SendCommandBlockMode", py::module_local())
286	        .value("none", BridgeSensor::SendCommandBlockMode::None)
287	        .value("Block", BridgeSensor::SendCommandBlockMode::Block)
288	        .value("BlockWithRetry", BridgeSensor::SendCommandBlockMode::BlockWithRetry);
289	
290	    py::enum_<BridgeSensor::FaSubscriberFilterType>(sensor, "FaSubscriberFilterType", py::module_local())
291	        .value("ExactMatch", BridgeSensor::FaSubscriberFilterType::ExactMatch)
292	        .value("AnyMatch", BridgeSensor::FaSubscriberFilterType::AnyMatch)
293	        .value("NotExactMatch", BridgeSensor::FaSubscriberFilterType::NotExactMatch);
294	
295	    py::enum_<BridgeSensor::AsciiSubscriberFilterType>(sensor, "AsciiSubscriberFilterType", py::module_local())
296	        .value("StartsWith", BridgeSensor::AsciiSubscriberFilterType::StartsWith)
297	        .value("DoesNotStartsWith", BridgeSensor::AsciiSubscriberFilterType::DoesNotStartWith);
298	
299	    py::class_<BridgeSensor::Fb00SubscriberFilter>(sensor, "Fb00SubscriberFilter", py::module_local())
300	        .def(py::init<>())
301	        .def(py::init<bool, bool>())
302	        .def_property("packet",
303	            [](const BridgeSensor::Fb00SubscriberFilter& filter) -> bool { return filter.packet; },
304	            [](BridgeSensor::Fb00SubscriberFilter& filter, bool value) -> void { filter.packet = value; }
305	        )
306	        .def_property("completedFaMessage",
307	            [](const BridgeSensor::Fb00SubscriberFilter& filter) -> bool { return filter.completedFaMessage; },
308	            [](BridgeSensor::Fb00SubscriberFilter& filter, bool value) -> void { filter.completedFaMessage = value; }
309	        )
310	        ;
311	
312	    sensor.def(py::init<BridgeSensor::MeasQueueMode>(), py::arg("mode") = BridgeSensor::MeasQueueMode::Force)
313	        .def(py::init<ByteBuffer&, ByteBuffer&, BridgeSensor::MeasQueueMode>(),
314	            py::arg("mainBuffer"), py::arg("fbBuffer"), py::arg("mode") = BridgeSensor::MeasQueueMode::Force)
315	        // Serial Connectivity
316	        .def("connect",
317	              [](BridgeSensor& vs, Serial_Base::PortName portName, BridgeSensor::BaudRate baudRate, bool monitorAsyncErrors) {
318	                throwIfError(vs.connect(portName, baudRate, monitorAsyncErrors));
319	              },
320	              py::arg("portName"), py::arg("baudRate"), py::arg("monitorAsyncErrors") = false
321	        )
322	        .def("connect",
323	              [](BridgeSensor& vs, Filesystem::FilePath& fileName) {
324	                throwIfError(vs.connect(fileName));
325	              }
326	        )
327	#if _VN_TCP_DRIVER
328	        .def("connect",
329	              [](BridgeSensor& vs, Serial_Base::PortName ipAddress, Serial_Base::PortName portNumber, bool monitorAsyncErrors) {
330	                throwIfError(vs.connect(ipAddress, portNumber, monitorAsyncErrors));
331	              },
332	              py::arg("ipAddress"), py::arg("portNumber"), py::arg("monitorAsyncErrors") = false
333	        )
334	#endif
335	        .def("autoConnect",
336	              [](BridgeSensor& vs, Serial_Base::PortName portName, bool monitorAsyncErrors) {
337	                throwIfError(vs.autoConnect(portName, monitorAsyncErrors));
338	              },
339	              py::arg("portName"), py::arg("monitorAsyncErrors") = false
340	        )
341	#if _VN_TCP_DRIVER
342	        .def("autoConnect",
343	              [](BridgeSensor& vs, Serial_Base::PortName ipAddress, Serial_Base::PortName portNumber, bool monitorAsyncErrors) {
344	                throwIfError(vs.autoConnect(ipAddress, portNumber, monitorAsyncErrors));
345	              },
346	              py::arg("ipAddress"), py::arg("portNumber"), py::arg("monitorAsyncErrors") = false
347	        )
348	#endif
349	        .def("disconnect", [] (BridgeSensor& vs) {
350	            vs.disconnect();
351	            vs.disableMonitor();
352	        } 
353	        )
354	        .def("reset",
355	        [](BridgeSensor& vs) {
356	            throwIfError(vs.reset(vs.asyncErrorThrowingEnabled()));
357	        }
358	        )
359	        ;
360	
361	    // Sensor aliases from Register module
362	    m.attr("Sensor").attr("BinaryOutputMeasurements") = m.attr("Registers").attr("System").attr("BinaryOutputMeasurements");
363	    m.attr("Sensor").attr("BaudRate") = m.attr("Registers").attr("System").attr("BaudRate").attr("BaudRates");
364	
365	    // Sensor aliases from Packet module
366	    m.attr("Sensor").attr("SyncByte") = m.attr("PacketDetails").attr("SyncByte");
367	
368	    py::class_<BinaryHeader>(m, "BinaryHeader")
369	        .def(py::init<>());
370	
371	}
372	}
373	// clang-format on
