        Baud230400 = 230400,
        Baud460800 = 460800,
        Baud921600 = 921600,
    };

    enum class SerialPort : uint8_t
    {
        ActiveSerial = 0,  ///< Set value on active serial port.
        Serial1 = 1,
        Serial2 = 2,
        Poll = static_cast<uint8_t>('?')
    };

