190	Error Sensor::changeBaudRate(const BaudRate newBaudRate, Registers::System::BaudRate::SerialPort serialPort) noexcept
191	{
192	    if constexpr (Config::CommandProcessor::commandProcQueueCapacity == 0) { return Error::CommandQueueFull; }
193	
194	    if (!_activeSerial->isSupportedBaudRate(static_cast<uint32_t>(newBaudRate))) { return Error::UnsupportedBaudRate; }
195	
196	    // Check to see if the serial port selected is the active serial port
197	    bool isActiveSerial{true};
198	    Error latestError;
199	    if (serialPort == Registers::System::BaudRate::SerialPort::ActiveSerial) { isActiveSerial = true; }
200	    else
201	    {
202	        Registers::System::BaudRate baudRateRegister;
203	        baudRateRegister.serialPort = Registers::System::BaudRate::SerialPort::Poll;
204	        latestError = readRegister(&baudRateRegister);
205	        if (latestError != VN::Error::None) { return latestError; }
206	        if (baudRateRegister.serialPort == Registers::System::BaudRate::SerialPort::Poll) { return Error::SerialReadFailed; }
207	        isActiveSerial = (serialPort == baudRateRegister.serialPort);
208	    }
209	
210	    // Change the sensor baud rate on the selected serial line
211	    Registers::System::BaudRate reg5;
212	    reg5.baudRate = newBaudRate;
213	    reg5.serialPort = serialPort;
214	    latestError = writeRegister(&reg5, true);
215	    if (latestError != Error::None) { return latestError; }
216	
217	    // Change the host baud rate if connected to active serial
218	    if (isActiveSerial)
219	    {
220	        // Host baud rate may switch quicker than unit can switch its baud rate, so we need to give time to the unit before sending any subsequent verify calls
221	        thisThread::sleepFor(50ms);  // Appears that the sensor may take time to correctly configure, even if changing from and to the same baud rate. Tested by
222	                                     // changing baud rate in loop, and occasionally received invalid checksum.
223	        latestError = changeHostBaudRate(newBaudRate);
224	    }
225	    return latestError;
226	}
